export function parseArgs(argv) {
  const result = { _: [] }
  let i = 0
  while (i < argv.length) {
    const arg = argv[i]
    if (!arg.startsWith('--')) {
      result._.push(arg)
      i += 1
    } else if (arg.includes('=')) {
      // --key=value syntax
      const [key, value] = arg.split('=', 2)
      result[key.slice(2)] = value
      i += 1
    } else {
      // --flag or --key (value follows)
      const key = arg.slice(2)
      if (i + 1 < argv.length && !argv[i + 1].startsWith('-')) {
        // --key value syntax
        result[key] = argv[i + 1]
        i += 2
      } else {
        // --flag boolean
        result[key] = true
        i += 1
      }
    }
  }
  return result
}

